diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index e1923a344179..40e1a76dbbf9 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3506,6 +3506,37 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
     return BinaryOperator::CreateMul(X, IncrementY);
   }

+  // If the operands have no common bits set:
+  // or (shl (udiv X, C), D), (urem X, C) -->
+  //   add (mul nuw (udiv X, C), (1<<D)-C), X
+  // iff (1<<D) > C
+  {
+    const APInt *C1, *C2, *ShAmt;
+    Value *X;
+    if (match(&I, m_c_DisjointOr(
+            m_OneUse(m_Shl(m_OneUse(m_UDiv(m_Value(X), m_APInt(C1))),
+                           m_APInt(ShAmt))),
+            m_OneUse(m_URem(m_Deferred(X), m_APInt(C2))))) &&
+        *C1 == *C2) {
+      unsigned ShAmtVal = ShAmt->getZExtValue();
+      if (ShAmtVal < C1->getBitWidth()) {
+        APInt ShlVal = APInt(C1->getBitWidth(), 1) << ShAmtVal;
+        if (ShlVal.ugt(*C1)) {
+          APInt MulVal = ShlVal - *C1;
+          Value *Div = nullptr;
+          if (match(Op0, m_Shl(m_Value(Div), m_APInt(ShAmt))))
+            Div = cast<Instruction>(Op0)->getOperand(0);
+          else
+            Div = cast<Instruction>(Op1)->getOperand(0);
+          Value *Mul = Builder.CreateMul(
+              Div, ConstantInt::get(Ty, MulVal), "reass.mul",
+              /*HasNUW=*/true);
+          return BinaryOperator::CreateAdd(Mul, X);
+        }
+      }
+    }
+  }
+
   // (A & C) | (B & D)
   Value *A, *B, *C, *D;
   if (match(Op0, m_And(m_Value(A), m_Value(C))) &&

log.expect_optimized_program:
define i32 @fold_add_udiv_urem_to_mul(i32 noundef %val) {
entry:
  %add = mul i32 %val, 3
  ret i32 %add
}
